import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("computes premium for a single sword (new customer, no surcharges)");
    it.todo("computes premium for a single amulet");
    it.todo("computes premium for a single staff");
    it.todo("computes premium for a single potion");
    it.todo("computes premium for a single component (rune) and rounds in MHPCO's favor");
    it.todo("offers a building block base premium for 3 alike components");
    it.todo("adds a 50% surcharge for a cursed item");
    it.todo("adds a 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("applies a 20% loyalty discount for customers with >= 2 years of business");
    it.todo("applies a 15% discount on a second contract instead of the first-insurance surcharge");
  });

  describe("claim", () => {
    it.todo("subtracts the 100 G deductible from the damage amount");
    it.todo("fully reimburses damage to items made of dragon material");
    it.todo("reimburses 50% of damage to items with enchantment >= 8");
    it.todo("caps the total payout at twice the insurance sum across multiple claims");
  });
});

