type ItemType = "sword" | "amulet" | "staff" | "potion";

interface Item {
  type: ItemType;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<ItemType, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const base = BASE_PREMIUM[step.items[0].type];
    const premium = Math.ceil(base * 1.10) + 5;
    return { premium };
  });
  return { results };
};

