type ItemType = "sword" | "amulet" | "staff" | "potion";

interface Item {
  type: ItemType;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<ItemType, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;

const quotePremium = (items: Item[]): number => {
  const base = BASE_PREMIUM[items[0].type];
  return Math.ceil((base * 110) / 100) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

