type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune";

interface Item {
  type: ItemType;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Damage {
  itemType: ItemType;
  amount: number;
}

interface Incident {
  cause: string;
  damages: Damage[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

type Step = QuoteStep | ClaimStep;

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: Step[];
}

type StepResult = { premium: number } | { payout: number; remainingCap: number };

const BASE_PREMIUM: Record<ItemType, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const INSURANCE_SUM: Record<ItemType, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
};

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const PROCESSING_FEE = 5;

const BUILDING_BLOCK_BASE = 60;
const CURSE_PERCENT = 150;
const HIGH_ENCHANT_PERCENT = 130;
const HIGH_ENCHANT_THRESHOLD = 5;
const FIRST_INSURANCE_PERCENT = 110;
const SUBSEQUENT_CONTRACT_PERCENT = 85;
const LOYALTY_PERCENT = 80;
const LOYALTY_THRESHOLD_YEARS = 2;

const isBuildingBlock = (items: Item[]): boolean =>
  items.length === 3 &&
  items.every((item) => item.type === items[0].type) &&
  items[0].type === "rune";

const applyPercent = (value: number, percent: number): number => (value * percent) / 100;

const itemBase = (item: Item): number => {
  let base = BASE_PREMIUM[item.type];
  if (item.cursed) base = applyPercent(base, CURSE_PERCENT);
  if (item.enchantment >= HIGH_ENCHANT_THRESHOLD) base = applyPercent(base, HIGH_ENCHANT_PERCENT);
  return base;
};

const baseForItems = (items: Item[]): number => {
  if (isBuildingBlock(items)) return BUILDING_BLOCK_BASE;
  return items.reduce((sum, item) => sum + itemBase(item), 0);
};

const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
  const contractPercent = quoteIndex === 0 ? FIRST_INSURANCE_PERCENT : SUBSEQUENT_CONTRACT_PERCENT;
  let amount = applyPercent(baseForItems(items), contractPercent);
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    amount = applyPercent(amount, LOYALTY_PERCENT);
  }
  return Math.ceil(amount) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items, scenario.customer, index) };
    }
    return { payout: undefined as unknown as number, remainingCap: undefined as unknown as number };
  });
  return { results };
};

content.text:
**Naming Evaluation**:
- `runScenario`: still fits — runs a scenario
- New code uses `policyStep`, `insuranceSum`, `damageTotal`, `payout`, `remainingCap` — all self-documenting
- The claim handling is currently inlined in `runScenario`, while quote handling is extracted to `quotePremium`. Asymmetry hurts intent.
- Decision: Extract `claimResult` to mirror `quotePremium`, so the dispatch in `runScenario` reads as a clean two-way choice.

**Current Code Mass** (the `runScenario` body only — the part being refactored):

```typescript
const results: StepResult[] = scenario.steps.map((step, index) => {
  if (step.op === "quote") {
    return { premium: quotePremium(step.items, scenario.customer, index) };
  }
  const policyStep = scenario.steps[step.policy] as QuoteStep;
  const insuranceSum = insuranceSumForItems(policyStep.items);
  const damageTotal = step.incident.damages.reduce((sum, d) => sum + d.amount, 0);
  const payout = damageTotal - DEDUCTIBLE;
  const remainingCap = CAP_MULTIPLIER * insuranceSum - payout;
  return { payout, remainingCap };
});
```
- Constants: `"quote"`, `DEDUCTIBLE`, `CAP_MULTIPLIER`, `0` (initial) = 4
- Bindings: `results`, `step`, `index`, `policyStep`, `insuranceSum`, `damageTotal`, `payout`, `remainingCap`, `sum`, `d` = 10
- Invocations: `.map`, `quotePremium`, `insuranceSumForItems`, `.reduce` = 4 (×2 = 8)
- Conditionals: `if` = 1 (×4 = 4)
- Loops: counted in invocations (.map, .reduce) — skip double count
- Assignments: `const` initializations don't count as reassignments in APP — 0

Total ≈ 4 + 10 + 8 + 4 = **26**

**Rule 1 - Tests Pass**: ✅ 11 passing

**Rule 2 - Reveals Intent**: Asymmetry — quote has a named helper, claim doesn't. Extracting a `claimResult` helper will reveal "scenario step → result" symmetry.

**Rule 3 - No Duplication**: None significant.

**Rule 4 - Fewest Elements**: The extraction adds one function but reduces the inline complexity of `runScenario`. Net wash on elements, but big gain on Rule 2.

Applying refactor:

